(()=>{let t=self;t.addEventListener("push",i=>{let n=i.data?i.data.json():{title:"CheckIt Notification",body:"You have a new update!"},o={body:n.body,icon:"/icon-192x192.png",badge:"/icon-192x192.png",data:n.url||"/"};i.waitUntil(t.registration.showNotification(n.title,o))}),t.addEventListener("notificationclick",i=>{i.notification.close(),i.waitUntil(t.clients.openWindow(i.notification.data||"/"))})})();